module top_module (
    input [1:0] l,
    output reg invalid
);

    always @(*) begin
        case (l)
            2'b00: invalid = 0;
            2'b01: invalid = 1;
            2'b10: invalid = 0;
            2'b11: invalid = 1;
            default: invalid = 0; // Default case
        endcase
    end
endmodule
